def detect_language() -> str:
    system_locale = QLocale.system().name().lower()
    return "pl" if system_locale.startswith("pl") else "en"


class I18N:
    def __init__(self, lang: str | None = None):
        self.lang = lang or detect_language()
        if self.lang not in TRANSLATIONS:
            self.lang = "en"

    def t(self, key: str, **kwargs) -> str:
        text = TRANSLATIONS.get(self.lang, TRANSLATIONS["en"]).get(key, key)
        return text.format(**kwargs) if kwargs else text
